patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index d824c40c401d..5c029962f3e7 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9801,7 +9801,12 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
                       return std::min(S, I);
                     }),
                 EltsPerVector);
-            Indices.push_back(OffsetReg1 % NumElts);
+            unsigned SecondIdx = OffsetReg1 % NumElts;
+            // Check if this index would be valid for extract operations.
+            // If not, we cannot use register-based shuffling.
+            if ((SecondIdx + EltsPerVector) > alignTo(NumElts, EltsPerVector))
+              return std::nullopt;
+            Indices.push_back(SecondIdx);
           }
           Idx = I - OffsetReg1;
         }

